using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // BREAKING CHANGE 1: EF Core 9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Existing documents use "Discriminator",
            // so explicitly preserve the old property name.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2: EF Core 9 no longer prefixes the id with the
            // discriminator. Existing documents use "Blog|<key>" format.
            // Use a custom ValueGenerator to preserve the legacy id format.
            entity.Property(b => b.Id)
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3: HasIndex() now throws for Cosmos provider.
            // Cosmos indexes are managed via the container's indexing policy in Azure,
            // not via EF model configuration. The HasIndex(b => b.Name) call is removed.
        });
    }
}

/// <summary>
/// Preserves the EF Core 8 Cosmos id format: "Discriminator|Key".
/// Existing documents have ids like "Blog|1" and must remain readable.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    protected override string GenerateValue(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
            ?? entry.Metadata.ShortName();
        var keyValues = entry.Metadata.FindPrimaryKey()!
            .Properties.Select(p => entry.Property(p.Name).CurrentValue);
        return $"{discriminator}|{string.Join("|", keyValues)}";
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

